<template>

  <div class="sign-in">
    <div class="form__card outer-pad">
      <header class="form__card__header">
        <div class="h1">Inicia Sesión</div>
      </header>
      <p class="form__card__description">Digita tu usuario y contraseña para acceder a tu cuenta.</p>
      <form @submit.prevent="checkPasswordandEmail()" action="submit" class="form__card__fields">
        <fieldset>
          <label for="" class="label--input">Correo electrónico</label>
          <input v-model="userEmail"
                 :class="{'form__card__fields--failed' : !isEmailValid}"
                 type="text">
          <div class="form__password__wrapper">
            <label for="" class="label--input">Contraseña</label>
            <input v-model="userPassword"
                  ref="inputPass"
                  :type="!passShown ? 'password' : 'text'"
                  :class="{'form__card__fields--failed' : !isPasswordValid}
                  ">
            <div class="icons__wrapper">
              <show-password v-if="!passShown" ref="showPass" @click="this.togglePass(true)"></show-password>
              <hide-password v-if="passShown" ref="hidePass" @click="this.togglePass(false)"></hide-password>
              <deleteText @click="this.userPassword = ''" class="icon__delete-text"> </deleteText>
            </div>
          </div>
        </fieldset>
        <button class="button--wide button--large">Inicia Sesión</button>
      </form>
      <footer class="form__card__footer">
        <p class="paragraph--dark">¿No tienes cuenta?<br><router-link :to='{name: "SignUp"}'>Registrate aquí.</router-link></p>
      </footer>
    </div>
    <router-view></router-view>
  </div>

</template>

<script>
// @ is an alias to /src
import hidePassword from '../../icons/textfields/hidePassword'
import showPassword from '../../icons/textfields/showPassword'
import deleteText from '../../icons/textfields/deleteText'

export default {
  name: 'SignIn',
  data () {
    return {
      userPassword: '',
      userEmail: '',
      isPasswordValid: true,
      isEmailValid: true,
      passShown: false
    }
  },
  methods: {
    checkPasswordandEmail (e) {
      const userPassword = 'holamundo'

      if (userPassword === this.userPassword) {
        this.isPasswordValid = true
        console.log('valid')
      } else {
        this.isPasswordValid = false
      }

      const userEmail = 'hola@mundo.com'

      if (userEmail === this.userEmail) {
        this.isEmailValid = true
        console.log('valid')
        this.$router.push('code-verification')
      } else {
        this.isEmailValid = false
      }
    },
    togglePass (show) {
      this.passShown = show
    }
  },
  components: {
    hidePassword,
    showPassword,
    deleteText
  }
}
</script>
