<template>
  <div class="sign-up">
    <sign-up-title v-if="step > 0"></sign-up-title>
    <div class="form__card outer-pad" v-if="step === 0">
      <header class="form__card__header">
        <div class="h1">Registrate</div>
        <router-link :to='{name: "SignIn"}'>Iniciar sesión</router-link>
      </header>
      <p class="form__card__description">Completa los datos para crear tu cuenta y acceder a los beneficios</p>
      <form @submit.prevent="checkPassword(); checkEmail();" action="submit" class="form__card__fields">
        <fieldset>
          <label for="" class="label--input">Correo electrónico</label>
          <input v-model="userEmail" ref="emailField" type="text">
          <div class="pass-input__wrapper">
            <label for="" class="label--input">Contraseña</label>
            <input ref="passField" v-model="userPassword" :type="!passShown ? 'password' : 'text'">
            <show-password v-if="!passShown" ref="showPass" @click="this.togglePass(true)"></show-password>
            <hide-password v-if="passShown" ref="hidePass" @click="this.togglePass(false)"></hide-password>
          </div>
        </fieldset>
        <label class="checkbox__container label--checkbox">Debe contener como mínimo una mayúscula, un número y un símbolo.
          <input type="checkbox" :checked="isPasswordValid">
          <span class="checkmark"></span>
        </label>
        <button class="button--wide button--large">Registrarme</button>
      </form>
      <footer class="form__card__footer">
        <p class="paragraph--dark">Al registrarme, estoy aceptando los <br><a href="">Términos y condiciones.</a></p>
      </footer>
    </div>
    <personal-data v-if="step === 1"></personal-data>
    <upload-i-d v-if="step === 2"></upload-i-d>
    <add-i-d v-if="step === 3"></add-i-d>
    <add-selfie v-if="step === 4"></add-selfie>
    <done-status v-if="step === 5"></done-status>
    <router-view></router-view>
  </div>
</template>

<script>
import PersonalData from './PersonalData'
import SignUpTitle from './SignUpTitle'
import UploadID from './UploadID.vue'
import AddID from './AddID.vue'
import AddSelfie from './AddSelfie.vue'
import doneStatus from '../../animations/doneStatus'
import hidePassword from '../../icons/textfields/hidePassword'
import showPassword from '../../icons/textfields/showPassword'

export default {
  name: 'SignUp',
  data () {
    return {
      step: 0,
      userPassword: '',
      hasUpperCase: false,
      hasLowerCase: false,
      hasSymbol: false,
      isPasswordValid: false,
      isEmailValid: false,
      userEmail: '',
      passShown: false,
      userData: {
        personalData: {
          fullName: '',
          birthdate: '',
          phone: '',
          cellphone: '',
          address: '',
          indications: ''
        },
        idData: {

        }
      }
    }
  },
  methods: {
    stepCount () {
      this.step++
    },
    checkPassword () {
      const symbols = /[ !@#$%^&*()_+\-=[\]{};':"\\|,.<>/?]/
      const upperCase = /[A-Z]/
      const lowerCase = /[a-z]/
      const isLength = this.userPassword.length > 8
      this.hasSymbol = symbols.test(this.userPassword)
      this.hasUpperCase = upperCase.test(this.userPassword)
      this.hasLowerCase = lowerCase.test(this.userPassword)
      this.hasSymbol && this.hasUpperCase && isLength ? this.isPasswordValid = true : this.isPasswordValid = false
      !this.isPasswordValid && this.$refs.passField.classList.add('form__card__fields--failed')
    },
    checkEmail () {
      const validEmailRegex = /^[a-zA-Z0-9.!#$%&'*+/=?^_`{|}~-]+@[a-zA-Z0-9-]+(?:\.[a-zA-Z0-9-]+)*$/
      this.isEmailValid = validEmailRegex.test(this.userEmail)
      !this.isEmailValid && this.$refs.emailField.classList.add('form__card__fields--failed')
    },
    togglePass (show) {
      this.passShown = show
    }
  },
  watch: {
    isEmailValid () {
      console.log('watch executed')
      this.isPasswordValid && this.$router.push('code-verification')
    }
  },
  beforeRouteEnter (to, from, next) {
    next(vm => {
      console.log(from.name)
      vm.prevLink = from.name
      if (from.name === 'codeverification') vm.stepCount()
    })
  },
  components: {
    PersonalData,
    SignUpTitle,
    UploadID,
    AddID,
    AddSelfie,
    doneStatus,
    showPassword,
    hidePassword
  }
}
</script>
